import React, { Component } from "react";
// import { Icon } from "@iconify/react";
// import reactIcon from "@iconify/icons-logos/react";
import profile from "../assets/images/profile.jpeg";
import { Button } from "react-bootstrap";
//logos: https://icon-sets.iconify.design/logos/

class About extends Component {
  render() {
    // if (this.props.sharedBasicInfo) {
    //   var profilepic = "../assets/images/" + this.props.sharedBasicInfo.image;
    // }

    if (this.props.resumeBasicInfo) {
      var sectionName = this.props.resumeBasicInfo.section_name.about;
      var hello = this.props.resumeBasicInfo.description_header;
      var about = this.props.resumeBasicInfo.description;
    }

    return (
      <section id="about">
        <div className="col-md-12">
          <h1 style={{ color: "black" }}>
            <span>{sectionName}</span>
          </h1>
          <div className="row center mx-auto mb-5">
            <div className="col-md-4 mb-5 center">
              <div className="polaroid">
                <span style={{ cursor: "auto" }}>
                  <img
                    height="350px"
                    width="auto"
                    src={profile}
                    alt="Avatar placeholder"
                  />
                  {/* <Icon
                    icon={htmlIcon}
                    style={{ fontSize: "400%", margin: "9% 5% 0 5%" }}
                  />
                  <Icon
                    icon={reactIcon}
                    style={{ fontSize: "400%", margin: "9% 5% 0 5%" }}
                  />
                  <Icon
                    icon={cppIcon}
                    style={{ fontSize: "400%", margin: "9% 5% 0 5%" }}
                  /> */}
                </span>
              </div>
            </div>

            <div className="col-md-8 center">
              <div className="col-md-10">
                <div className="card">
                  <div className="card-header">
                    <span
                      className="iconify"
                      data-icon="emojione:red-circle"
                      data-inline="false"
                    ></span>{" "}
                    &nbsp;{" "}
                    <span
                      className="iconify"
                      data-icon="twemoji:yellow-circle"
                      data-inline="false"
                    ></span>{" "}
                    &nbsp;{" "}
                    <span
                      className="iconify"
                      data-icon="twemoji:green-circle"
                      data-inline="false"
                    ></span>
                  </div>
                  <div
                    className="card-body font-trebuchet text-justify ml-3 mr-3"
                    style={{
                      height: "auto",
                      fontSize: "132%",
                      lineHeight: "200%",
                    }}
                  >
                    <br />
                    <span className="wave">{hello} </span>
                    <br />
                    <br />
                    {about}
                    <br/>
                    <br/>
                    <div className="aboutButtons">
                      <Button className="buttons" href="https://drive.google.com/file/d/1N5yD1cvpJPzr8H9kdIVGctLEAB7FLB44/view?usp=sharing">Resume</Button>
                      <Button className="buttons" href="https://drive.google.com/file/d/1G-OuxSzTCIQSag-3Ls65PzwAz_0LHE-p/view?usp=sharing">CV</Button>
                      <Button className="buttons" href="mailto:mfgunawan01@gmail.com">Contact</Button>
                    </div>

                    
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    );
  }
}

export default About;
